insert into public.pages (slug, title, hero_kicker, hero_heading_html, hero_lede, stats_jsonb, status) values ('library', 'Library', 'The Lending Library', 'Over <em>2,400 books</em>,<br />free to borrow.', 'Take two home at a time. Three weeks to return. No late fees, no paperwork.', '{"stats":[{"label":"Books on shelf","value":"2,412"},{"label":"Active borrowers","value":"312"},{"label":"Languages","value":"18"},{"label":"New this month","value":"47"}],"houseRules":[{"n":"01","title":"Borrow two at a time.","body":"Write your name, book, and date in the ledger."},{"n":"02","title":"Keep them three weeks.","body":"If you need longer, pencil in an extension."},{"n":"03","title":"Return to the drop-box.","body":"Right by the door. No waiting, no staff needed."},{"n":"04","title":"Donate if you can.","body":"Orange shelf in the back. We sort weekly."}],"featured":{"kicker":"Featured shelf · April","headline":"Books in translation,","accent":"chosen by translators.","body":"Fourteen titles picked by the translators who’d kill for them. Margaret Jull Costa, Sean Cotter, Sophie Hughes, and Jennifer Croft each pulled three."}}'::jsonb, 'published') on conflict (slug) do update set title=excluded.title, hero_kicker=excluded.hero_kicker, hero_heading_html=excluded.hero_heading_html, hero_lede=excluded.hero_lede, stats_jsonb=excluded.stats_jsonb;
