insert into public.featured_supper (id, kicker, title, italic_accent, description, menu_title, courses, price_full, price_member, price_wine_pairing, status) values (true, 'May 8 · Prix fixe', 'Poetry on ', 'Small Plates.', 'A six-course tasting menu paired to six poems. The kitchen cooks what we’ve been reading; the room reads what we’re eating. ₹4,080, ₹3,060 for members, wine pairing ₹2,050.', 'Read & eaten.', '[{"number":"01","dish":"Pan con tomate","attribution":"Lorca, “Canción del naranjo seco”"},{"number":"02","dish":"Boquerones & lemon","attribution":"Szymborska, “Possibilities”"},{"number":"03","dish":"Almond-saffron soup","attribution":"Berry, “The Peace of Wild Things”"},{"number":"04","dish":"Braised octopus","attribution":"Neruda, “Ode to the Sea”"},{"number":"05","dish":"Membrillo & Manchego","attribution":"Plath, “Blackberrying”"},{"number":"06","dish":"Orange-olive-oil cake","attribution":"Oliver, “The Summer Day”"}]'::jsonb, 4080, 3060, 2050, 'published') on conflict (id) do update set kicker=excluded.kicker, title=excluded.title, italic_accent=excluded.italic_accent, description=excluded.description, menu_title=excluded.menu_title, courses=excluded.courses, price_full=excluded.price_full, price_member=excluded.price_member, price_wine_pairing=excluded.price_wine_pairing;
