insert into public.faqs (question, answer, is_open_by_default, sort_order, status) values ('Do I need to be a member to come in?', 'Not at all. Walk in any time we’re open — read, borrow a book, order a plate. Membership just unlocks the book clubs, supper priority, and a quarterly book on us.', FALSE, 0, 'published');
insert into public.faqs (question, answer, is_open_by_default, sort_order, status) values ('Can I work here on my laptop?', 'Before 5pm, absolutely — Wi-Fi is free, outlets at every other table. After 5, we dim the lights and ask laptops to close so the room can breathe.', FALSE, 1, 'published');
insert into public.faqs (question, answer, is_open_by_default, sort_order, status) values ('Do you host private events?', 'Yes — we buy out the room for book launches, small weddings, birthday suppers, and translation parties. Email events@ and we’ll send a one-pager.', FALSE, 2, 'published');
insert into public.faqs (question, answer, is_open_by_default, sort_order, status) values ('Is the menu vegetarian-friendly?', 'Roughly 70% of our small plates are vegetarian; most can be made vegan. Gluten-free bread is baked fresh twice a week.', FALSE, 3, 'published');
insert into public.faqs (question, answer, is_open_by_default, sort_order, status) values ('Can I bring kids?', 'Of course — we have a small children’s shelf and crayons by the window. After 8pm the room tilts a little quieter, so that’s more of an adult hour.', FALSE, 4, 'published');
insert into public.faqs (question, answer, is_open_by_default, sort_order, status) values ('How do I donate a book?', 'Leave it on the orange shelf by the door, or hand it to whoever’s at the counter. We keep everything worth keeping and pass the rest to the Reading Public Library.', FALSE, 5, 'published');
insert into public.journal_posts (slug, category, cover_color, title_html, excerpt, author_name, author_initial, read_minutes, is_featured, is_sidebar, sidebar_kicker, sort_order, status) values ('on-reading-very-slowly', 'Essay', 'taupe', 'On reading <em>very slowly</em> — three months inside <em>The Magic Mountain.</em>', NULL, 'Marisol Reyes', 'M', 14, TRUE, FALSE, 'Featured', 0, 'published') on conflict (slug) do update set category=excluded.category, cover_color=excluded.cover_color, title_html=excluded.title_html, excerpt=excluded.excerpt, author_name=excluded.author_name, author_initial=excluded.author_initial, read_minutes=excluded.read_minutes, is_featured=excluded.is_featured, is_sidebar=excluded.is_sidebar, sidebar_kicker=excluded.sidebar_kicker, sort_order=excluded.sort_order;
insert into public.journal_posts (slug, category, cover_color, title_html, excerpt, author_name, author_initial, read_minutes, is_featured, is_sidebar, sidebar_kicker, sort_order, status) values ('minor-detail-staff-pick', 'Essay', 'taupe', 'Why we’re pressing <em>Minor Detail</em> into every hand this month.', 'Shibli’s sentences sit so quietly on the page they make the room itself feel like it’s listening.', 'Ava Park', 'A', 6, FALSE, TRUE, 'Staff Pick', 1, 'published') on conflict (slug) do update set category=excluded.category, cover_color=excluded.cover_color, title_html=excluded.title_html, excerpt=excluded.excerpt, author_name=excluded.author_name, author_initial=excluded.author_initial, read_minutes=excluded.read_minutes, is_featured=excluded.is_featured, is_sidebar=excluded.is_sidebar, sidebar_kicker=excluded.sidebar_kicker, sort_order=excluded.sort_order;
insert into public.journal_posts (slug, category, cover_color, title_html, excerpt, author_name, author_initial, read_minutes, is_featured, is_sidebar, sidebar_kicker, sort_order, status) values ('jull-costa-interview', 'Essay', 'taupe', 'Margaret Jull Costa on the word that broke her heart for a week.', 'A translator’s notebook: what to do when a sentence is faithful, legal, and still wrong.', 'Julien', 'J', 9, FALSE, TRUE, 'Conversation', 2, 'published') on conflict (slug) do update set category=excluded.category, cover_color=excluded.cover_color, title_html=excluded.title_html, excerpt=excluded.excerpt, author_name=excluded.author_name, author_initial=excluded.author_initial, read_minutes=excluded.read_minutes, is_featured=excluded.is_featured, is_sidebar=excluded.is_sidebar, sidebar_kicker=excluded.sidebar_kicker, sort_order=excluded.sort_order;
insert into public.journal_posts (slug, category, cover_color, title_html, excerpt, author_name, author_initial, read_minutes, is_featured, is_sidebar, sidebar_kicker, sort_order, status) values ('case-for-the-very-long-book', 'Essay', 'purple', 'The case for <em>the very long book.</em>', 'There is a particular kind of reader formed only by books you live inside for two seasons. Notes from a year of doorstoppers.', 'Marisol', 'M', 14, FALSE, FALSE, NULL, 3, 'published') on conflict (slug) do update set category=excluded.category, cover_color=excluded.cover_color, title_html=excluded.title_html, excerpt=excluded.excerpt, author_name=excluded.author_name, author_initial=excluded.author_initial, read_minutes=excluded.read_minutes, is_featured=excluded.is_featured, is_sidebar=excluded.is_sidebar, sidebar_kicker=excluded.sidebar_kicker, sort_order=excluded.sort_order;
insert into public.journal_posts (slug, category, cover_color, title_html, excerpt, author_name, author_initial, read_minutes, is_featured, is_sidebar, sidebar_kicker, sort_order, status) values ('sophie-hughes-lost-found', 'Interview', 'orange', 'Sophie Hughes on <em>what gets lost, what gets found.</em>', 'The translator of Fernanda Melchor visits the cafe for a long afternoon of coffee and two very exact questions.', 'Julien', 'J', 9, FALSE, FALSE, NULL, 4, 'published') on conflict (slug) do update set category=excluded.category, cover_color=excluded.cover_color, title_html=excluded.title_html, excerpt=excluded.excerpt, author_name=excluded.author_name, author_initial=excluded.author_initial, read_minutes=excluded.read_minutes, is_featured=excluded.is_featured, is_sidebar=excluded.is_sidebar, sidebar_kicker=excluded.sidebar_kicker, sort_order=excluded.sort_order;
insert into public.journal_posts (slug, category, cover_color, title_html, excerpt, author_name, author_initial, read_minutes, is_featured, is_sidebar, sidebar_kicker, sort_order, status) values ('pencil-notes-used-austerlitz', 'Marginalia', 'ink', 'Pencil notes from <em>a used Austerlitz.</em>', 'A previous reader left twenty-seven pencil stars in our copy of Sebald. We tried to understand what they meant.', 'Ava', 'A', 7, FALSE, FALSE, NULL, 5, 'published') on conflict (slug) do update set category=excluded.category, cover_color=excluded.cover_color, title_html=excluded.title_html, excerpt=excluded.excerpt, author_name=excluded.author_name, author_initial=excluded.author_initial, read_minutes=excluded.read_minutes, is_featured=excluded.is_featured, is_sidebar=excluded.is_sidebar, sidebar_kicker=excluded.sidebar_kicker, sort_order=excluded.sort_order;
insert into public.journal_posts (slug, category, cover_color, title_html, excerpt, author_name, author_initial, read_minutes, is_featured, is_sidebar, sidebar_kicker, sort_order, status) values ('twelve-things-room-said-ernaux', 'Club Notes', 'pink', 'Twelve things <em>the room said</em> about Ernaux.', 'Transcripts from our Slow Fiction Club’s March meeting — what a first-time reader noticed that the rest of us had stopped seeing.', 'Marisol', 'M', 8, FALSE, FALSE, NULL, 6, 'published') on conflict (slug) do update set category=excluded.category, cover_color=excluded.cover_color, title_html=excluded.title_html, excerpt=excluded.excerpt, author_name=excluded.author_name, author_initial=excluded.author_initial, read_minutes=excluded.read_minutes, is_featured=excluded.is_featured, is_sidebar=excluded.is_sidebar, sidebar_kicker=excluded.sidebar_kicker, sort_order=excluded.sort_order;
insert into public.journal_posts (slug, category, cover_color, title_html, excerpt, author_name, author_initial, read_minutes, is_featured, is_sidebar, sidebar_kicker, sort_order, status) values ('almond-saffron-soup-neruda', 'Recipe', 'lime', 'Almond-saffron soup, <em>as read by Neruda.</em>', 'The house soup, named after the ode. Recipe in a paragraph, serves four, tastes like someone read it to you.', 'Rafa', 'R', 5, FALSE, FALSE, NULL, 7, 'published') on conflict (slug) do update set category=excluded.category, cover_color=excluded.cover_color, title_html=excluded.title_html, excerpt=excluded.excerpt, author_name=excluded.author_name, author_initial=excluded.author_initial, read_minutes=excluded.read_minutes, is_featured=excluded.is_featured, is_sidebar=excluded.is_sidebar, sidebar_kicker=excluded.sidebar_kicker, sort_order=excluded.sort_order;
insert into public.journal_posts (slug, category, cover_color, title_html, excerpt, author_name, author_initial, read_minutes, is_featured, is_sidebar, sidebar_kicker, sort_order, status) values ('quiet-hour-whats-in-it', 'Essay', 'taupe', 'The quiet hour, <em>and what’s in it.</em>', 'After 8pm the lights drop and the laptops close. What actually happens in that hour, from someone who sits through all of them.', 'Ava', 'A', 11, FALSE, FALSE, NULL, 8, 'published') on conflict (slug) do update set category=excluded.category, cover_color=excluded.cover_color, title_html=excluded.title_html, excerpt=excluded.excerpt, author_name=excluded.author_name, author_initial=excluded.author_initial, read_minutes=excluded.read_minutes, is_featured=excluded.is_featured, is_sidebar=excluded.is_sidebar, sidebar_kicker=excluded.sidebar_kicker, sort_order=excluded.sort_order;
insert into public.journal_posts (slug, category, cover_color, title_html, excerpt, author_name, author_initial, read_minutes, is_featured, is_sidebar, sidebar_kicker, sort_order, status) values ('week-inside-a-single-paragraph', 'Translator Diary', 'orange', 'A week inside <em>a single paragraph.</em>', 'Guest diarist Sean Cotter on Cărtărescu’s Solenoid — and the week he lost to three consecutive subordinate clauses.', 'Sean', 'S', 13, FALSE, FALSE, NULL, 9, 'published') on conflict (slug) do update set category=excluded.category, cover_color=excluded.cover_color, title_html=excluded.title_html, excerpt=excluded.excerpt, author_name=excluded.author_name, author_initial=excluded.author_initial, read_minutes=excluded.read_minutes, is_featured=excluded.is_featured, is_sidebar=excluded.is_sidebar, sidebar_kicker=excluded.sidebar_kicker, sort_order=excluded.sort_order;
insert into public.journal_posts (slug, category, cover_color, title_html, excerpt, author_name, author_initial, read_minutes, is_featured, is_sidebar, sidebar_kicker, sort_order, status) values ('poetry-small-plates-origin', 'Club Notes', 'purple', 'Why <em>Poetry & Small Plates</em> nearly didn’t happen.', 'The origin story of our strangest supper: a chef, six poets, and an overbooked Friday night.', 'Rafa', 'R', 8, FALSE, FALSE, NULL, 10, 'published') on conflict (slug) do update set category=excluded.category, cover_color=excluded.cover_color, title_html=excluded.title_html, excerpt=excluded.excerpt, author_name=excluded.author_name, author_initial=excluded.author_initial, read_minutes=excluded.read_minutes, is_featured=excluded.is_featured, is_sidebar=excluded.is_sidebar, sidebar_kicker=excluded.sidebar_kicker, sort_order=excluded.sort_order;
insert into public.journal_posts (slug, category, cover_color, title_html, excerpt, author_name, author_initial, read_minutes, is_featured, is_sidebar, sidebar_kicker, sort_order, status) values ('jennifer-croft-invisible-translator', 'Interview', 'pink', 'Jennifer Croft on <em>the invisible translator.</em>', 'A long conversation about names on covers, authorship, and what a reader actually owes the second writer of a book.', 'Julien', 'J', 12, FALSE, FALSE, NULL, 11, 'published') on conflict (slug) do update set category=excluded.category, cover_color=excluded.cover_color, title_html=excluded.title_html, excerpt=excluded.excerpt, author_name=excluded.author_name, author_initial=excluded.author_initial, read_minutes=excluded.read_minutes, is_featured=excluded.is_featured, is_sidebar=excluded.is_sidebar, sidebar_kicker=excluded.sidebar_kicker, sort_order=excluded.sort_order;
insert into public.about_manifesto (id, kicker, heading_html, paragraphs) values (true, 'Manifesto', 'We built the <em>cafe we wanted</em> to read in.', '[{"drop_cap":"T","body":"apas Reading Cafe is a love letter to two things: the slow afternoon, and the long novel. We opened in the fall of 2021 with forty chairs, eight hundred books, and a small kitchen that does exactly six things well. We did not open to scale. We opened so there would be a room, on Haven Street, with enough sunlight to read in and enough food to stay for."},{"drop_cap":"M","body":"ost bookshops rush you. Most cafes turn their tables. We do neither. The tapas come out in waves so you can keep reading. The library along the north wall is free to borrow from. The book clubs meet around one long walnut table, and anyone is welcome for the first visit on the house."},{"drop_cap":"W","body":"e are a three-person team with a standing rule: if a book is worth our shelves, it’s worth a paragraph in our staff notes. We hand-write them on cream cards, we update them every Monday, and we’ve never lost a single one."}]'::jsonb) on conflict (id) do update set kicker=excluded.kicker, heading_html=excluded.heading_html, paragraphs=excluded.paragraphs;
