insert into public.about_timeline (year, heading, body, sort_order) values ('2021', 'The lease on Haven St.', 'Marisol signed for the 900sqft storefront on a Tuesday. We painted on Saturday; the first pot of coffee was Sunday.', 0);
insert into public.about_timeline (year, heading, body, sort_order) values ('2022', 'The long table arrived.', 'Built by a neighbor from a single walnut slab. It seats 24. The Slow Fiction Club began the week it was finished.', 1);
insert into public.about_timeline (year, heading, body, sort_order) values ('2023', 'Lending library, no cards.', 'The ledger went up. We promised no late fees, no paperwork — just a name, a date, and a return window of three weeks.', 2);
insert into public.about_timeline (year, heading, body, sort_order) values ('2026', 'Six clubs, one room.', 'Translators in Translation, First-Draft Friday, and the Poetry Supper now share the same table, in rotation.', 3);
insert into public.about_compromises (number_label, title_html, body, bg_color, sort_order) values ('01', 'The room <em>takes its time.</em>', 'No table turns. No laptops after five. Coffee refills are on us. If you’re reading something long, we’d rather you finished the chapter than opened your wallet again.', 'lime', 0);
insert into public.about_compromises (number_label, title_html, body, bg_color, sort_order) values ('02', 'Books <em>are for borrowing.</em>', 'The lending library is free, without cards, without sign-up. We trust you. We have never, in five years, lost more than eleven books — and nine of those came back.', 'lime', 1);
insert into public.about_compromises (number_label, title_html, body, bg_color, sort_order) values ('03', 'Small plates, <em>big conversations.</em>', 'Six tapas a night, cooked by Rafa. No tasting menus, no pairings unless you ask. The food is here so the reading and talking can go longer, not shorter.', 'lime', 2);
