insert into public.press_quotes (source, quote, context, sort_order) values ('The Boston Globe', 'The rare bookshop that expects you to stay for dinner — and makes it worth your while.', 'Dining · 2024', 0);
insert into public.press_quotes (source, quote, context, sort_order) values ('Boston Magazine', 'A room so quiet you can hear the pages turn, with tapas sharp enough to cut through it.', 'Best of · 2025', 1);
insert into public.press_quotes (source, quote, context, sort_order) values ('Eater Boston', 'The menu is short. The wine list is shorter. The book list is enormous. That’s the whole pitch.', 'First look · 2023', 2);
insert into public.press_quotes (source, quote, context, sort_order) values ('A regular, on Google', 'I have read more in the last year at Tapas than in the five before it. I don’t know what that says about me.', '★★★★★ · 2026', 3);
